function makeLR(i) {
  const cons = CONSIGNORS[i % CONSIGNORS.length];
  const cnee = CONSIGNEES[i % CONSIGNEES.length];
  const veh = VEHICLES[i % VEHICLES.length];
  const tr = TRANSPORTERS[i % TRANSPORTERS.length];
  const freight = 8000 + (i % 7) * 1450;
  const door = (i % 3) * 500, handling = 300 + (i % 4) * 150;
  const gst = Math.round((freight + door + handling) * 0.12);
  const total = freight + door + handling + gst;
  const advance = i % 2 === 0 ? Math.round(total * 0.4) : 0;
  const mm = String((i % 12) + 1).padStart(2, "0");
  const dd = String((i % 27) + 1).padStart(2, "0");
  return {
    id: `VLL/25/${mm}/${String(56 + i).padStart(5, "0")}`,
    date: `2025-${mm}-${dd}`, bookingTime: `${String(9 + (i % 8)).padStart(2, "0")}:${String((i * 7) % 60).padStart(2, "0")}`,
    entryUser: ["op_anita", "op_vikram", "op_anita"][i % 3],
    consignor: cons, consignee: cnee, vehicle: veh, transporter: tr,
    route: ROUTES[i % ROUTES.length], payType: ["TBB", "To Pay", "Paid", "TBB", "FOC"][i % 5],
    deliveryType: ["Door Delivery", "Godown Delivery", "Warehouse Pickup", "Customer Pickup"][i % 4],
    items: [{ pkgs: 12 + (i % 9), pkgType: ["Pallet", "Box", "Carton"][i % 3], nature: "Auto Components", asn: `ASN${90210 + i}`, invNo: `INV/${2300 + i}`, invDate: `2025-${mm}-0${(i % 8) + 1}`, part: "Brake Assembly Kit", qty: 240 + i * 5, weight: 1250 + i * 30, value: 145000 + i * 5500 }],
    ewb: { number: String(481200000000 + i * 137).slice(0, 12), expiry: `2025-${mm}-${String((i % 27) + 5).padStart(2, "0")}`, load: i % 2 === 0 ? "Full load" : "Part load" },
    freight, door, handling, insurance: 0, gst, advance, total, balance: total - advance,
    status: ["Delivered", "In Transit", "Booked", "In Transit", "Delivered"][i % 5],
    pod: i % 3 === 0 ? `2025-${mm}-${String((i % 27) + 3).padStart(2, "0")}` : "",
    mathadi: (i % 4) * 350, vistarBillNo: `VB/25-26/${120 + i}`, vistarBillDate: `2025-${mm}-${String((i % 27) + 2).padStart(2, "0")}`,
    vistarBillAmount: total + 1500, vistarMargin: 1500 + (i % 5) * 400, advancePaidBy: ["Vistar", "Customer", "Vistar"][i % 3], tripLeadBy: ["Operations", "Sales", "Operations"][i % 3],
  };
}
const LRS = Array.from({ length: 14 }, (_, i) => makeLR(i));

