/* Reports */
function Reports() {
  const cards = [
    { t: "LR Generated Today", v: "6", ic: FileText, c: T.plum }, { t: "Route-wise Dispatch", v: "5 routes", ic: RouteIcon, c: T.orange },
    { t: "Vehicle Utilization", v: "78%", ic: Truck, c: T.amber }, { t: "Customer-wise LR", v: "3 active", ic: Users, c: T.red },
  ];
  const byRoute = useMemo(() => { const m = {}; LRS.forEach((l) => m[l.route] = (m[l.route] || 0) + 1); return Object.entries(m); }, []);
  const maxR = Math.max(...byRoute.map((r) => r[1]));
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 18, flexWrap: "wrap", gap: 10 }}>
        <div><h1 style={{ margin: 0, fontSize: 24, fontWeight: 800, color: T.ink }}>Reports</h1><p style={{ margin: "4px 0 0", color: T.slate, fontSize: 14 }}>Daily · Monthly · Accounts</p></div>
        <div style={{ display: "flex", gap: 8 }}><Btn kind="ghost" sm icon={Calendar}>This Month</Btn><Btn kind="ghost" sm icon={Download}>Export PDF</Btn></div>
      </div>
      <div style={{ display: "flex", gap: 14, flexWrap: "wrap", marginBottom: 14 }}>
        {cards.map((c) => <Stat key={c.t} icon={c.ic} label={c.t} value={c.v} tint={c.c} />)}
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }} className="vl-dash-grid">
        <Card>
          <SectionTitle icon={RouteIcon}>Route-wise Dispatch</SectionTitle>
          {byRoute.map(([r, n]) => (
            <div key={r} style={{ marginBottom: 14 }}>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 5 }}><span style={{ fontWeight: 600 }}>{r}</span><span style={{ color: T.slate, fontWeight: 700 }}>{n} LR</span></div>
              <div style={{ height: 8, background: T.mist, borderRadius: 99 }}><div style={{ height: "100%", width: `${(n / maxR) * 100}%`, background: GRAD, borderRadius: 99 }} /></div>
            </div>
          ))}
        </Card>
        <Card>
          <SectionTitle icon={Wallet}>Freight Summary</SectionTitle>
          {[["Total Billed", LRS.reduce((s, l) => s + l.total, 0), T.ink], ["Advance Received", LRS.reduce((s, l) => s + l.advance, 0), T.ok], ["Pending Freight", LRS.filter((l) => l.balance > 0).reduce((s, l) => s + l.balance, 0), T.red], ["Vistar Margin", LRS.reduce((s, l) => s + l.vistarMargin, 0), T.plum]].map(([k, v, c]) => (
            <div key={k} style={{ display: "flex", justifyContent: "space-between", padding: "11px 0", borderBottom: `1px solid ${T.line}` }}><span style={{ color: T.slate, fontWeight: 600 }}>{k}</span><span style={{ fontWeight: 800, color: c }}>{inr(v)}</span></div>
          ))}
        </Card>
      </div>
    </div>
  );
}

